{
  "query": "mutation Signup($username: String!, $email: String!, $password: String!) {\n  signup(username: $username, email: $email, password: $password) {\n    success\n    message\n    token\n    user { _id username email created_at updated_at }\n  }\n}",
  "variables": {
    "username": "demo_user",
    "email": "demo_user@example.com",
    "password": "Password123!"
  }
}

{
  "query": "query Login($usernameOrEmail: String!, $password: String!) {\n  login(usernameOrEmail: $usernameOrEmail, password: $password) {\n    success\n    message\n    token\n    user { _id username email }\n  }\n}",
  "variables": {
    "usernameOrEmail": "demo_user",
    "password": "Password123!"
  }
}

{
  "query": "query {
  getAllEmployees {
    success
    message
    count
    employees { _id first_name last_name email gender designation salary date_of_joining department employee_photo }
  }
}"
}

{
  "query": "mutation AddEmployee($employee: EmployeeInput!) {\n  addEmployee(employee: $employee) {\n    success\n    message\n    employee { _id first_name last_name email gender designation salary date_of_joining department employee_photo }\n  }\n}",
  "variables": {
    "employee": {
      "first_name": "Mina",
      "last_name": "Rahimi",
      "email": "mina.rahimi@example.com",
      "gender": "Female",
      "designation": "Business Analyst",
      "salary": 54000,
      "date_of_joining": "2026-01-10",
      "department": "Operations",
      "employee_photo": ""
    }
  }
}

{
  "query": "query SearchByEid($eid: ID!) {\n  searchEmployeeByEid(eid: $eid) {\n    success\n    message\n    employee { _id first_name last_name email designation department }\n  }\n}",
  "variables": {
    "eid": "{{eid}}"
  }
}

{
  "query": "mutation UpdateEmp($eid: ID!, $updates: EmployeeUpdateInput!) {\n  updateEmployeeByEid(eid: $eid, updates: $updates) {\n    success\n    message\n    employee { _id first_name last_name salary designation department }\n  }\n}",
  "variables": {
    "eid": "{{eid}}",
    "updates": {
      "salary": 60000,
      "designation": "Senior Business Analyst"
    }
  }
}

{
  "query": "mutation DeleteEmp($eid: ID!) {\n  deleteEmployeeByEid(eid: $eid) {\n    success\n    message\n    deletedEmployeeId\n  }\n}",
  "variables": {
    "eid": "{{eid}}"
  }
}

{
  "query": "query SearchByDesignationOrDept($designation: String, $department: String) {\n  searchEmployeesByDesignationOrDepartment(designation: $designation, department: $department) {\n    success\n    message\n    count\n    employees { _id first_name last_name designation department }\n  }\n}",
  "variables": {
    "designation": "Engineer",
    "department": null
  }
}
